// FetchURLPreview handles the POST /preview request
func FetchURLPreview(ctx echo.Context) error {
	reqBody := new(PreviewRequest)
	if err := ctx.Bind(reqBody); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON"})
	}

	// Validate URL
	parsedURL, err := url.Parse(reqBody.URL)
	if err != nil || parsedURL.Scheme == "" || parsedURL.Host == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL format"})
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Only HTTP/HTTPS URLs are allowed"})
	}

	// Fetch the URL
	client := &http.Client{Timeout: 5 * time.Second}

	req, err := http.NewRequest(http.MethodGet, parsedURL.String(), nil)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to create request"})
	}
	req.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	resp, err := client.Do(req)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": fmt.Sprintf("Remote server returned %d", resp.StatusCode)})
	}

	// Limit reading to 1MB to prevent memory issues with large files
	body, err := io.ReadAll(io.LimitReader(resp.Body, 1024*1024))
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response body"})
	}

	title, description := extractTitleAndDescription(body)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// extractTitleAndDescription parses HTML to find the title and meta description
func extractTitleAndDescription(htmlContent []byte) (string, string) {
	var title, description string
	tokenizer := html.NewTokenizer(bytes.NewReader(htmlContent))

	for {
		tokenType := tokenizer.Next()
		if tokenType == html.ErrorToken {
			break
		}

		token := tokenizer.Token()

		switch tokenType {
		case html.StartTagToken:
			if token.Data == "title" {
				// The next token should be the text content of the title
				if tokenizer.Next() == html.TextToken {
					title = strings.TrimSpace(tokenizer.Token().Data)
				}
			}
			// Fallthrough to check meta tags in StartTagToken
			fallthrough
		case html.SelfClosingTagToken:
			if token.Data == "meta" {
				var nameAttr, propertyAttr, contentAttr string
				for _, attr := range token.Attr {
					switch attr.Key {
					case "name":
						nameAttr = strings.ToLower(attr.Val)
					case "property":
						propertyAttr = strings.ToLower(attr.Val)
					case "content":
						contentAttr = attr.Val
					}
				}

				// Standard description or OpenGraph description
				if (nameAttr == "description" || propertyAttr == "og:description") && description == "" {
					description = contentAttr
				}
			}
		}

		// Optimization: if we have both, we can stop early
		if title != "" && description != "" {
			break
		}
	}

	return title, description
}

