	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response body"})
	}

	title, description := extractTitleAndDescription(body)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       strings.TrimSpace(title),
		Description: strings.TrimSpace(description),
	})
}

// extractTitleAndDescription parses HTML bytes to find the <title> and <meta name="description">
func extractTitleAndDescription(htmlContent []byte) (string, string) {
	var title, description string
	doc, err := html.Parse(bytes.NewReader(htmlContent))
	if err != nil {
		return "", ""
	}

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			switch n.Data {
			case "title":
				if n.FirstChild != nil && n.FirstChild.Type == html.TextNode {
					title = n.FirstChild.Data
				}
			case "meta":
				var nameOrProperty, content string
				for _, attr := range n.Attr {
					key := strings.ToLower(attr.Key)
					if key == "name" || key == "property" {
						nameOrProperty = strings.ToLower(attr.Val)
					} else if key == "content" {
						content = attr.Val
					}
				}
				// Support standard meta description and OpenGraph description
				if (nameOrProperty == "description" || nameOrProperty == "og:description") && description == "" {
					description = content
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)
	return title, description
}

