	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "Target URL returned a non-200 status code"})
	}

	title, description := parseHTML(resp.Body)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// parseHTML traverses the HTML document to find the title and meta description.
func parseHTML(r io.Reader) (title, description string) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", ""
	}

	var f func(*html.Node)
	f = func(n *html.Node) {
		// Extract <title> tag
		if n.Type == html.ElementNode && n.Data == "title" && n.FirstChild != nil {
			if title == "" {
				title = strings.TrimSpace(n.FirstChild.Data)
			}
		}

		// Extract <meta> tags for description
		if n.Type == html.ElementNode && n.Data == "meta" {
			var isDesc bool
			var content string
			for _, attr := range n.Attr {
				key := strings.ToLower(attr.Key)
				val := strings.ToLower(attr.Val)

				// Check for standard description or OpenGraph description
				if (key == "name" && val == "description") || (key == "property" && val == "og:description") {
					isDesc = true
				}
				if key == "content" {
					content = attr.Val
				}
			}
			if isDesc && description == "" {
				description = strings.TrimSpace(content)
			}
		}

		// Recursive traversal
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}

	f(doc)
	return title, description
}

func main() {
	e := echo.New()

	// Middleware
	e.Use(middleware.Logger())
	e.Use(middleware.Recover())

	// Routes
	e.POST("/preview", FetchURLPreview)

	// Start server
	e.Logger.Fatal(e.Start(":8080"))
}

