// FetchURLPreview handles POST requests to extract title and description from a URL.
// It is registered under the /preview path.
func FetchURLPreview(ctx echo.Context) error {
	req := new(PreviewRequest)
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid request body"})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "The 'url' field is required"})
	}

	// Requirement: Set the timeout to 3 seconds when fetching the provided URL.
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusServiceUnavailable, map[string]string{"error": "Failed to fetch URL: " + err.Error()})
	}
	defer resp.Body.Close()

	// Read a limited portion of the response body to extract metadata efficiently.
	// 64KB is generally sufficient to contain the <head> section of most HTML pages.
	limitReader := io.LimitReader(resp.Body, 64*1024)
	bodyBytes, err := io.ReadAll(limitReader)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read page content"})
	}
	html := string(bodyBytes)

	var result PreviewResponse

	// Extract Page Title: <title>...</title>
	// (?is) flag: i = case-insensitive, s = let dot match newlines.
	titleRegex := regexp.MustCompile(`(?is)<title[^>]*>(.*?)</title>`)
	if matches := titleRegex.FindStringSubmatch(html); len(matches) > 1 {
		result.Title = strings.TrimSpace(matches[1])
	}

	// Extract Meta Description: <meta name="description" content="...">
	// We handle both common attribute orders: name before content and content before name.
	descRegex1 := regexp.MustCompile(`(?i)<meta\s+[^>]*name=["']description["'][^>]*content=["']([^"']*)["']`)
	descRegex2 := regexp.MustCompile(`(?i)<meta\s+[^>]*content=["']([^"']*)["'][^>]*name=["']description["']`)

	if matches := descRegex1.FindStringSubmatch(html); len(matches) > 1 {
		result.Description = strings.TrimSpace(matches[1])
	} else if matches := descRegex2.FindStringSubmatch(html); len(matches) > 1 {
		result.Description = strings.TrimSpace(matches[1])
	}

	return ctx.JSON(http.StatusOK, result)
}

