// PreviewRequest defines the input structure
type PreviewRequest struct {
	URL string `json:"url"`
}

// PreviewResponse defines the output structure
type PreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
	Error       string `json:"error,omitempty"`
}

// FetchURLPreview handles the POST /preview request
func FetchURLPreview(ctx echo.Context) error {
	req := new(PreviewRequest)
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, PreviewResponse{Error: "Invalid request body"})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, PreviewResponse{Error: "URL is required"})
	}

	// Set timeout to 3 seconds as required
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, PreviewResponse{Error: "Failed to fetch URL: " + err.Error()})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadGateway, PreviewResponse{Error: "Target URL returned non-200 status"})
	}

	// Parse HTML content
	doc, err := html.Parse(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, PreviewResponse{Error: "Failed to parse HTML"})
	}

	var title, description string
	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract Title
			if n.Data == "title" && n.FirstChild != nil {
				title = n.FirstChild.Data
			}

			// Extract Meta Description
			if n.Data == "meta" {
				var name, content string
				for _, attr := range n.Attr {
					if strings.ToLower(attr.Key) == "name" {
						name = attr.Val
					}
					if strings.ToLower(attr.Key) == "content" {
						content = attr.Val
					}
				}
				if strings.ToLower(name) == "description" {
					description = content
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       strings.TrimSpace(title),
		Description: strings.TrimSpace(description),
	})
}

func main() {
	e := echo.New()

	// Middleware
	e.Use(middleware.Logger())
	e.Use(middleware.Recover())

	// Routes
	e.POST("/preview", FetchURLPreview)

	// Start server
	e.Logger.Fatal(e.Start(":8080"))
}

