// isUnsafeIP checks if an IP address belongs to a private, loopback, or local network.
func isUnsafeIP(ip net.IP) bool {
	return ip.IsLoopback() ||
		ip.IsLinkLocalUnicast() ||
		ip.IsLinkLocalMulticast() ||
		ip.IsPrivate() ||
		ip.IsUnspecified()
}

// isUnsafeURL performs a preliminary check on the URL before dialing.
func isUnsafeURL(u *url.URL) bool {
	if u.Scheme != "http" && u.Scheme != "https" {
		return true
	}
	host := u.Hostname()
	if host == "" {
		return true
	}
	// If the host is an IP literal, check it immediately.
	if ip := net.ParseIP(host); ip != nil {
		return isUnsafeIP(ip)
	}
	// Basic check for common local names.
	lowHost := strings.ToLower(host)
	if lowHost == "localhost" || lowHost == "localhost.localdomain" {
		return true
	}
	return false
}

// getSafeClient returns an http.Client configured to prevent SSRF.
func getSafeClient() *http.Client {
	return &http.Client{
		Timeout: 5 * time.Second,
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			if len(via) >= 3 {
				return fmt.Errorf("too many redirects")
			}
			if isUnsafeURL(req.URL) {
				return fmt.Errorf("redirect to unsafe URL blocked")
			}
			return nil
		},
		Transport: &http.Transport{
			DialContext: (&net.Dialer{
				Timeout:   2 * time.Second,
				KeepAlive: 30 * time.Second,
				// Control is called after DNS resolution but before connection.
				Control: func(network, address string, c syscall.RawConn) error {
					host, _, err := net.SplitHostPort(address)
					if err != nil {
						return err
					}
					ip := net.ParseIP(host)
					if ip != nil && isUnsafeIP(ip) {
						return fmt.Errorf("access to private network is prohibited")
					}
					return nil
				},
			}).DialContext,
			ForceAttemptHTTP2:     true,
			MaxIdleConns:          100,
			IdleConnTimeout:       90 * time.Second,
			TLSHandshakeTimeout:   10 * time.Second,
			ExpectContinueTimeout: 1 * time.Second,
		},
	}
}

func FetchURLPreview(ctx echo.Context) error {
	req := new(PreviewRequest)
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON"})
	}

	parsedURL, err := url.Parse(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL format"})
	}

	if isUnsafeURL(parsedURL) {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Access to this URL is restricted"})
	}

	client := getSafeClient()
	httpReq, err := http.NewRequestWithContext(ctx.Request().Context(), http.MethodGet, parsedURL.String(), nil)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to create request"})
	}
