	titleRegex := regexp.MustCompile(`(?i)<title[^>]*>([^<]*)</title>`)
	descRegex := regexp.MustCompile(`(?i)<meta\s+[^>]*name=["']description["'][^>]*content=["']([^"']*)["']`)
	descRegex2 := regexp.MustCompile(`(?i)<meta\s+[^>]*content=["']([^"']*)["'][^>]*name=["']description["']`)

	var title, description string

	if matches := titleRegex.FindSubmatch(htmlContent); len(matches) > 1 {
		title = html.UnescapeString(string(matches[1]))
	}

	if matches := descRegex.FindSubmatch(htmlContent); len(matches) > 1 {
		description = html.UnescapeString(string(matches[1]))
	} else if matches := descRegex2.FindSubmatch(htmlContent); len(matches) > 1 {
		description = html.UnescapeString(string(matches[1]))
	}

	return strings.TrimSpace(title), strings.TrimSpace(description)
}

