type PreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
	Error       string `json:"error,omitempty"`
}

// FetchURLPreview handles the extraction of title and meta description from a given URL
func FetchURLPreview(c echo.Context) error {
	req := new(PreviewRequest)
	if err := c.Bind(req); err != nil {
		return c.JSON(http.StatusBadRequest, PreviewResponse{Error: "Invalid JSON body"})
	}

	if req.URL == "" {
		return c.JSON(http.StatusBadRequest, PreviewResponse{Error: "URL field is required"})
	}

	// Set the timeout to 3 seconds as required
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(req.URL)
	if err != nil {
		return c.JSON(http.StatusInternalServerError, PreviewResponse{Error: "Failed to fetch URL: " + err.Error()})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return c.JSON(resp.StatusCode, PreviewResponse{Error: "URL returned non-OK status: " + resp.Status})
	}

	// Parse the HTML content
	title, description := parseHTML(resp.Body)

	return c.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// parseHTML extracts the title and meta description using a streaming tokenizer
func parseHTML(body io.Reader) (string, string) {
	var title, description string
	tokenizer := html.NewTokenizer(body)

	for {
		tokenType := tokenizer.Next()

		switch tokenType {
		case html.ErrorToken:
			// End of document or error
			return title, description

		case html.StartTagToken, html.SelfClosingTagToken:
			token := tokenizer.Token()

			// Handle <title> tag
			if token.Data == "title" {
				tokenType = tokenizer.Next()
				if tokenType == html.TextToken {
					title = strings.TrimSpace(tokenizer.Token().Data)
				}
			}

			// Handle <meta> tags
			if token.Data == "meta" {
				var nameAttr, contentAttr string
				for _, attr := range token.Attr {
					if strings.ToLower(attr.Key) == "name" {
						nameAttr = strings.ToLower(attr.Val)
					}
					if strings.ToLower(attr.Key) == "content" {
						contentAttr = attr.Val
					}
				}

				if nameAttr == "description" {
					description = contentAttr
				}
			}
		}

		// Optimization: If both found, we can stop early
		if title != "" && description != "" {
			return title, description
		}
	}
}

func main() {
	e := echo.New()

	// Middleware
	e.Use(middleware.Logger())
	e.Use(middleware.Recover())

	// Routes
	e.POST("/preview", FetchURLPreview)

	// Start server
	e.Logger.Fatal(e.Start(":8080"))
}

