package main

import (
	"net/http"
	"strings"
	"time"

	"github.com/labstack/echo/v4"
	"golang.org/x/net/html"
)

// PreviewRequest defines the structure for the incoming JSON payload.
type PreviewRequest struct {
	URL string `json:"url"`
}

// PreviewResponse defines the structure for the outgoing JSON response.
type PreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

// FetchURLPreview is the Echo handler that fetches a URL and extracts its metadata.
// It is registered under the /preview path.
func FetchURLPreview(ctx echo.Context) error {
	req := new(PreviewRequest)
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON body"})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL field is required"})
	}

	// Create an HTTP client with a 3-second timeout requirement.
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Fetch the content from the provided URL.
	resp, err := client.Get(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL: " + err.Error()})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "Target URL returned non-200 status"})
	}

	// Parse the HTML content.
	doc, err := html.Parse(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to parse HTML"})
	}

	title, description := extractMetadata(doc)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       strings.TrimSpace(title),
		Description: strings.TrimSpace(description),
	})
}

// extractMetadata traverses the HTML node tree to find the title and meta description.
func extractMetadata(n *html.Node) (title, description string) {
	var crawler func(*html.Node)
	crawler = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract <title>
			if n.Data == "title" {
				for c := n.FirstChild; c != nil; c = c.NextSibling {
					if c.Type == html.TextNode {
						title += c.Data
					}
				}
			}

			// Extract <meta name="description" content="...">
			if n.Data == "meta" {
				var isDesc bool
				var content string
				for _, attr := range n.Attr {
					key := strings.ToLower(attr.Key)
					val := strings.ToLower(attr.Val)

					if key == "name" && val == "description" {
						isDesc = true
					}
					if key == "content" {
						content = attr.Val
					}
				}
				if isDesc && content != "" {
					description = content
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			crawler(c)
		}
	}
	crawler(n)
	return
}

func main() {
	// Initialize Echo instance
	e := echo.New()

	// Register the handler under the /preview path
	e.POST("/preview", FetchURLPreview)

	// Start the server
	e.Logger.Fatal(e.Start(":8080"))
}

