package main

import (
	"fmt"
	"html"
	"io"
	"net/http"
	"net/url"
	"regexp"
	"strings"
	"time"

	"github.com/labstack/echo/v4"
)

// Request body
type PreviewRequest struct {
	URL string `json:"url"`
}

// Response body
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
}

func main() {
	e := echo.New()

	// Register the route
	e.POST("/preview", FetchURLPreview)

	// Start the server
	e.Logger.Fatal(e.Start(":8080"))
}

// FetchURLPreview handles the URL preview request
func FetchURLPreview(ctx echo.Context) error {
	req := new(PreviewRequest)
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON"})
	}

	// Validate URL
	parsedURL, err := url.Parse(req.URL)
	if err != nil || parsedURL.Scheme == "" || parsedURL.Host == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL format"})
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Only HTTP/HTTPS URLs are allowed"})
	}

	// Fetch the URL
	client := &http.Client{Timeout: 5 * time.Second}

	// Create request with a proper User-Agent
	httpReq, err := http.NewRequestWithContext(ctx.Request().Context(), http.MethodGet, parsedURL.String(), nil)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to create request"})
	}
	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": fmt.Sprintf("HTTP %d", resp.StatusCode)})
	}

	// Limit reading to 1MB to prevent potential memory issues with large files
	limitReader := io.LimitReader(resp.Body, 1024*1024)
	body, err := io.ReadAll(limitReader)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response body"})
	}

	title, description := extractTitleAndDescription(body)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// extractTitleAndDescription parses the HTML content to find title and meta description
func extractTitleAndDescription(htmlContent []byte) (string, string) {
	contentStr := string(htmlContent)

	var title string
	// Regex to find <title> content, case-insensitive and matching across multiple lines
	titleRegex := regexp.MustCompile(`(?is)<title>(.*?)</title>`)
	titleMatches := titleRegex.FindStringSubmatch(contentStr)
	if len(titleMatches) > 1 {
		title = strings.TrimSpace(html.UnescapeString(titleMatches[1]))
	}

	var description string
	// Regex to find <meta name="description" content="..."> or <meta content="..." name="description">
	// Meta tags can have attributes in different orders
	descRegex1 := regexp.MustCompile(`(?i)<meta\s+[^>]*name=["']description["']\s+content=["']([^"']*)["']`)
	descRegex2 := regexp.MustCompile(`(?i)<meta\s+[^>]*content=["']([^"']*)["']\s+name=["']description["']`)

	if matches := descRegex1.FindStringSubmatch(contentStr); len(matches) > 1 {
		description = strings.TrimSpace(html.UnescapeString(matches[1]))
	} else if matches := descRegex2.FindStringSubmatch(contentStr); len(matches) > 1 {
		description = strings.TrimSpace(html.UnescapeString(matches[1]))
	}

	return title, description
}

