		Title:       title,
		Description: description,
	})
}

// extractTitleAndDescription parses the HTML to find the <title> and <meta name="description">
func extractTitleAndDescription(htmlContent []byte) (string, string) {
	doc, err := html.Parse(bytes.NewReader(htmlContent))
	if err != nil {
		return "", ""
	}

	var title, description string
	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode && n.Data == "title" && n.FirstChild != nil {
			if n.FirstChild.Type == html.TextNode {
				title = strings.TrimSpace(n.FirstChild.Data)
			}
		}
		if n.Type == html.ElementNode && n.Data == "meta" {
			var isDesc bool
			var content string
			for _, attr := range n.Attr {
				if strings.ToLower(attr.Key) == "name" && strings.ToLower(attr.Val) == "description" {
					isDesc = true
				}
				if strings.ToLower(attr.Key) == "content" {
					content = attr.Val
				}
			}
			if isDesc {
				description = strings.TrimSpace(content)
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}
	f(doc)

	return title, description
}

func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)
	e.Logger.Fatal(e.Start(":8080"))
}

