type PreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

// FetchURLPreview is an Echo handler that fetches a URL and extracts its title and meta description.
// It is registered under the /preview path.
func FetchURLPreview(ctx echo.Context) error {
	reqBody := new(PreviewRequest)
	if err := ctx.Bind(reqBody); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON body"})
	}

	if reqBody.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL field is required"})
	}

	// Requirement: Set the timeout to 3 seconds when fetching the provided URL.
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(reqBody.URL)
	if err != nil {
		return ctx.JSON(http.StatusRequestTimeout, map[string]string{"error": "Failed to fetch URL: " + err.Error()})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "Target URL returned status: " + resp.Status})
	}

	title, description := parseHTMLMetadata(resp.Body)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// parseHTMLMetadata parses the HTML stream to extract the <title> and <meta name="description">.
func parseHTMLMetadata(r io.Reader) (string, string) {
	var title, description string
	tokenizer := html.NewTokenizer(r)

	for {
		tokenType := tokenizer.Next()
		if tokenType == html.ErrorToken {
			break
		}

		token := tokenizer.Token()

		// Extract Title
		if tokenType == html.StartTagToken && token.Data == "title" {
			if nextType := tokenizer.Next(); nextType == html.TextToken {
				title = strings.TrimSpace(tokenizer.Token().Data)
			}
		}

		// Extract Meta Description
		if (tokenType == html.StartTagToken || tokenType == html.SelfClosingTagToken) && token.Data == "meta" {
			var nameAttr, contentAttr string
			for _, attr := range token.Attr {
				key := strings.ToLower(attr.Key)
				if key == "name" {
					nameAttr = strings.ToLower(attr.Val)
				} else if key == "content" {
					contentAttr = attr.Val
				}
			}

			if nameAttr == "description" && description == "" {
				description = contentAttr
			}
		}

		// Optimization: If we found both, we could stop, but meta tags can appear anywhere in the head.
		// For robustness, we continue until the tokenizer finishes or hits an error.
	}

	return title, description
}

func main() {
