import (
	"net/http"
	"strings"
	"time"

	"github.com/labstack/echo/v4"
	"golang.org/x/net/html"
)

// PreviewRequest defines the input JSON structure
type PreviewRequest struct {
	URL string `json:"url"`
}

// PreviewResponse defines the output JSON structure
type PreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

// FetchURLPreview fetches a URL and extracts its title and meta description.
// It is registered under the /preview path.
func FetchURLPreview(ctx echo.Context) error {
	req := new(PreviewRequest)
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid request body"})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL field is required"})
	}

	// Requirement: Set the timeout to 3 seconds when fetching provided URL
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL: " + err.Error()})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "Target URL returned status: " + resp.Status})
	}

	doc, err := html.Parse(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to parse HTML content"})
	}

	result := &PreviewResponse{}
	extractMetadata(doc, result)

	return ctx.JSON(http.StatusOK, result)
}

// extractMetadata traverses the HTML node tree to find <title> and <meta name="description">
func extractMetadata(n *html.Node, res *PreviewResponse) {
	if n.Type == html.ElementNode {
		switch n.Data {
		case "title":
			// Extract text content from the first child of the title tag
			if res.Title == "" && n.FirstChild != nil && n.FirstChild.Type == html.TextNode {
				res.Title = strings.TrimSpace(n.FirstChild.Data)
			}
		case "meta":
			var name, content string
			for _, attr := range n.Attr {
				attrKey := strings.ToLower(attr.Key)
				if attrKey == "name" {
					name = strings.ToLower(attr.Val)
				} else if attrKey == "content" {
					content = attr.Val
				}
			}
			if name == "description" && res.Description == "" {
				res.Description = strings.TrimSpace(content)
			}
		}
	}

	// Recursively traverse child nodes
	for c := n.FirstChild; c != nil; c = c.NextSibling {
		extractMetadata(c, res)
	}
}

func main() {
	e := echo.New()

	// Register handler under the /preview path as required
	e.POST("/preview", FetchURLPreview)

	// Start the server on port 8080
	e.Logger.Fatal(e.Start(":8080"))
}

