// PreviewRequest defines the input structure for the POST request body
type PreviewRequest struct {
	URL string `json:"url"`
}

// PreviewResponse defines the output structure for the JSON response
type PreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

// FetchURLPreview handles the POST request to extract metadata from a given URL
func FetchURLPreview(ctx echo.Context) error {
	reqBody := new(PreviewRequest)
	if err := ctx.Bind(reqBody); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON body"})
	}

	if reqBody.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL is required"})
	}

	// Create an HTTP client with a 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(reqBody.URL)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL: " + err.Error()})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "Target URL returned status " + resp.Status})
	}

	// Parse the HTML content
	doc, err := html.Parse(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to parse HTML content"})
	}

	preview := &PreviewResponse{}
	extractMetadata(doc, preview)

	return ctx.JSON(http.StatusOK, preview)
}

// extractMetadata recursively traverses the HTML nodes to find title and description
func extractMetadata(n *html.Node, res *PreviewResponse) {
	if n.Type == html.ElementNode {
		// Extract Title
		if n.Data == "title" && res.Title == "" && n.FirstChild != nil {
			res.Title = strings.TrimSpace(n.FirstChild.Data)
		}

		// Extract Meta Description
		if n.Data == "meta" {
			var isDescription bool
			var content string
			for _, attr := range n.Attr {
				key := strings.ToLower(attr.Key)
				val := strings.ToLower(attr.Val)

				if key == "name" && val == "description" {
					isDescription = true
				}
				if key == "content" {
					content = attr.Val
				}
			}
			if isDescription && res.Description == "" {
				res.Description = strings.TrimSpace(content)
			}
		}
	}

	for c := n.FirstChild; c != nil; c = c.NextSibling {
		extractMetadata(c, res)
	}
}

func main() {
	e := echo.New()

	// Register the handler under the /preview path
	e.POST("/preview", FetchURLPreview)

	// Start the server
	e.Logger.Fatal(e.Start(":8080"))
}

