// isForbiddenIP checks if an IP is private, loopback, or link-local to prevent SSRF
func isForbiddenIP(ip net.IP) bool {
	if ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() || ip.IsPrivate() {
		return true
	}
	// Handle IPv4-mapped IPv6 addresses
	if ip4 := ip.To4(); ip4 != nil {
		return ip4.IsLoopback() || ip4.IsLinkLocalUnicast() || ip4.IsPrivate()
	}
	return false
}

// safeClient is a hardened http.Client to prevent SSRF and DNS Rebinding
var safeClient = &http.Client{
	Timeout: 5 * time.Second,
	Transport: &http.Transport{
		DialContext: (&net.Dialer{
			Timeout:   3 * time.Second,
			KeepAlive: 30 * time.Second,
			// Control is called after DNS resolution but before connection
			Control: func(network, address string, c syscall.RawConn) error {
				host, _, err := net.SplitHostPort(address)
				if err != nil {
