// extractTitleAndDescription parses the HTML content using regex for simplicity.
// In a production environment, using an HTML parser like golang.org/x/net/html is recommended.
func extractTitleAndDescription(htmlContent []byte) (string, string) {
	contentStr := string(htmlContent)
	title := ""
	titleMatch := regexp.MustCompile(`(?i)<title[^>]*>(.*?)</title>`).FindStringSubmatch(contentStr)
	if len(titleMatch) > 1 {
		title = strings.TrimSpace(titleMatch[1])
	}

	description := ""
	// Regex for <meta name="description" content="..."> or <meta content="..." name="description">
	descRegex := regexp.MustCompile(`(?i)<meta\s+[^>]*name=["']description["'][^>]*content=["']([^"']*)["']`)
	descMatch := descRegex.FindStringSubmatch(contentStr)
	if len(descMatch) > 1 {
		description = strings.TrimSpace(descMatch[1])
	} else {
		// Try alternative attribute order
		descRegexAlt := regexp.MustCompile(`(?i)<meta\s+[^>]*content=["']([^"']*)["'][^>]*name=["']description["']`)
		descMatchAlt := descRegexAlt.FindStringSubmatch(contentStr)
		if len(descMatchAlt) > 1 {
			description = strings.TrimSpace(descMatchAlt[1])
		}
	}

	return title, description
}

func main() {
	e := echo.New()

	// Register the handler
	e.POST("/preview", FetchURLPreview)

	e.Logger.Fatal(e.Start(":8080"))
}

