// PreviewRequest defines the input structure for the URL preview request.
type PreviewRequest struct {
	URL string `json:"url"`
}

// PreviewResponse defines the output structure containing page metadata.
type PreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
