// FetchURLPreview is the Echo handler that fetches a URL and extracts its title and meta description.
func FetchURLPreview(ctx echo.Context) error {
	req := new(PreviewRequest)
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid request body"})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL field is required"})
	}

	// Create an HTTP client with a 3-second timeout as required.
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL: " + err.Error()})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "Target URL returned non-200 status code"})
	}

	title, description := parseHTML(resp.Body)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// parseHTML helper function to extract title and meta description using a tokenizer.
func parseHTML(r io.Reader) (string, string) {
	var title, description string
	tokenizer := html.NewTokenizer(r)

	for {
		tokenType := tokenizer.Next()

		switch tokenType {
		case html.ErrorToken:
			// End of document or error
			return title, description

		case html.StartTagToken:
			token := tokenizer.Token()
			if token.Data == "title" {
				// The next token should be the text content of the title
				if tokenizer.Next() == html.TextToken {
					title = strings.TrimSpace(tokenizer.Token().Data)
				}
			}
			// Meta tags can be StartTag or SelfClosingTag
			if token.Data == "meta" {
				description = extractDescription(token, description)
			}

		case html.SelfClosingTagToken:
			token := tokenizer.Token()
			if token.Data == "meta" {
				description = extractDescription(token, description)
			}
		}
	}
}

// extractDescription looks for the 'description' name attribute in a meta tag.
func extractDescription(token html.Token, currentDesc string) string {
	var isDescription bool
	var content string

	for _, attr := range token.Attr {
		if strings.ToLower(attr.Key) == "name" && strings.ToLower(attr.Val) == "description" {
			isDescription = true
		}
		if strings.ToLower(attr.Key) == "content" {
			content = attr.Val
		}
	}

	if isDescription {
		return content
	}
	return currentDesc
}

func main() {
	e := echo.New()

	// Middleware
	e.Use(middleware.Logger())
	e.Use(middleware.Recover())

	// Routes
	e.POST("/preview", FetchURLPreview)

	// Start server
	e.Logger.Fatal(e.Start(":8080"))
