					title = strings.TrimSpace(z.Token().Data)
				}
			}

			// Extract Meta Description
			if t.Data == "meta" {
				var nameAttr, contentAttr string
				for _, attr := range t.Attr {
					if strings.ToLower(attr.Key) == "name" {
						nameAttr = strings.ToLower(attr.Val)
					}
					if strings.ToLower(attr.Key) == "content" {
						contentAttr = attr.Val
					}
				}
				if nameAttr == "description" {
					description = contentAttr
				}
			}
		}

		// Optimization: If we found both, we could stop, but usually it's safer to 
		// continue a bit as titles and descriptions appear early in the <head>.
		if title != "" && description != "" {
