package main

import (
	"bytes"
	"fmt"
	"io"
	"net/http"
	"net/url"
	"strings"
	"time"

	"github.com/labstack/echo/v4"
	"golang.org/x/net/html"
)

// PreviewRequest defines the input body
type PreviewRequest struct {
	URL string `json:"url"`
}

// PreviewResponse defines the output body
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
}

func main() {
	e := echo.New()

	// Register the handler under the /preview path
	e.POST("/preview", FetchURLPreview)

	e.Logger.Fatal(e.Start(":8080"))
}

// FetchURLPreview handles the POST request to extract metadata from a URL
func FetchURLPreview(ctx echo.Context) error {
	reqBody := new(PreviewRequest)
	if err := ctx.Bind(reqBody); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON"})
	}

	// Validate URL
	parsedURL, err := url.Parse(reqBody.URL)
	if err != nil || parsedURL.Scheme == "" || parsedURL.Host == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL format"})
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Only HTTP/HTTPS URLs are allowed"})
	}

	// Fetch the URL with a timeout
	client := &http.Client{Timeout: 5 * time.Second}
	req, err := http.NewRequest(http.MethodGet, reqBody.URL, nil)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to create request"})
	}
	req.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	resp, err := client.Do(req)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": fmt.Sprintf("Target returned HTTP %d", resp.StatusCode)})
	}

	// Read response body (limiting size to 1MB to prevent OOM)
	body, err := io.ReadAll(io.LimitReader(resp.Body, 1024*1024))
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response body"})
	}

	title, description := extractTitleAndDescription(body)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// extractTitleAndDescription parses HTML bytes to find title and meta description
func extractTitleAndDescription(htmlContent []byte) (string, string) {
	doc, err := html.Parse(bytes.NewReader(htmlContent))
	if err != nil {
		return "", ""
	}

	var title, description string
	var crawler func(*html.Node)
	crawler = func(node *html.Node) {
		// Extract Title
		if node.Type == html.ElementNode && node.Data == "title" {
			if node.FirstChild != nil {
				title = node.FirstChild.Data
			}
		}

		// Extract Meta Description
		if node.Type == html.ElementNode && node.Data == "meta" {
			var name, content string
			for _, attr := range node.Attr {
				attrKey := strings.ToLower(attr.Key)
				if attrKey == "name" {
					name = strings.ToLower(attr.Val)
				} else if attrKey == "content" {
					content = attr.Val
				}
			}
			if name == "description" {
				description = content
			}
		}

		// Traverse the tree
		for child := node.FirstChild; child != nil; child = child.NextSibling {
			crawler(child)
		}
	}

	crawler(doc)

	return strings.TrimSpace(title), strings.TrimSpace(description)
}

