)

// PreviewRequest represents the expected JSON body for the POST request.
type PreviewRequest struct {
	URL string `json:"url"`
}

// PreviewResponse represents the JSON response containing the page metadata.
type PreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

// FetchURLPreview is the handler that fetches a URL and extracts its title and meta description.
// Registered under the /preview path.
func FetchURLPreview(ctx echo.Context) error {
	req := new(PreviewRequest)
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "invalid request body"})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "url field is required"})
	}

	// Set the timeout to 3 seconds as per requirements.
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "failed to fetch URL: " + err.Error()})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "external site returned status: " + resp.Status})
	}

	// Parse the HTML content. We limit the reader to 1MB to avoid processing massive files.
	title, description := extractMetadata(io.LimitReader(resp.Body, 1024*1024))

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       strings.TrimSpace(title),
		Description: strings.TrimSpace(description),
	})
}

// extractMetadata parses the HTML and returns the content of <title> and <meta name="description">.
func extractMetadata(r io.Reader) (string, string) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", ""
	}

	var title, description string
	var crawler func(*html.Node) bool
	crawler = func(n *html.Node) bool {
		// Extract Title
		if n.Type == html.ElementNode && n.Data == "title" {
			if n.FirstChild != nil && n.FirstChild.Type == html.TextNode {
				if title == "" {
					title = n.FirstChild.Data
				}
			}
		}

		// Extract Meta Description
		if n.Type == html.ElementNode && n.Data == "meta" {
			var nameAttr, contentAttr string
			for _, attr := range n.Attr {
				key := strings.ToLower(attr.Key)
				if key == "name" {
					nameAttr = strings.ToLower(attr.Val)
				} else if key == "content" {
					contentAttr = attr.Val
				}
			}
			if nameAttr == "description" && description == "" {
				description = contentAttr
			}
		}

		// Stop early if both are found
		if title != "" && description != "" {
			return true
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			if crawler(c) {
				return true
			}
		}
		return false
	}

	crawler(doc)
	return title, description
}

func main() {
	e := echo.New()

	// Register the handler under the /preview path
	e.POST("/preview", FetchURLPreview)

	// Start the server
	e.Logger.Fatal(e.Start(":8080"))
