package main

import (
	"io"
	"net/http"
	"regexp"
	"strings"
	"time"

	"github.com/labstack/echo/v4"
	"github.com/labstack/echo/v4/middleware"
)

// PreviewRequest defines the expected JSON body for the POST request
type PreviewRequest struct {
	URL string `json:"url"`
}

// PreviewResponse defines the JSON structure returned to the client
type PreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

var (
	// Regex to extract <title> content (case-insensitive, handles multiline)
	titleRegex = regexp.MustCompile(`(?is)<title[^>]*>(.*?)</title>`)
	// Regex to extract <meta name="description" content="...">
	descRegex1 = regexp.MustCompile(`(?i)<meta[^>]*name=["']description["'][^>]*content=["']([^"']*)["']`)
	// Regex to extract <meta content="..." name="description">
	descRegex2 = regexp.MustCompile(`(?i)<meta[^>]*content=["']([^"']*)["'][^>]*name=["']description["']`)
)

// FetchURLPreview handles the URL fetching and metadata extraction logic
func FetchURLPreview(ctx echo.Context) error {
	req := new(PreviewRequest)
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid request body"})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL field is required"})
	}

	// Initialize HTTP client with a mandatory 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL: " + err.Error()})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "Target URL returned status: " + resp.Status})
	}

	// Limit reader to 1MB to prevent excessive memory usage for very large HTML files
	bodyBytes, err := io.ReadAll(io.LimitReader(resp.Body, 1024*1024))
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response body"})
	}

	htmlContent := string(bodyBytes)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       extractTitle(htmlContent),
		Description: extractDescription(htmlContent),
	})
}

// extractTitle searches for the <title> tag in the HTML string
func extractTitle(html string) string {
	match := titleRegex.FindStringSubmatch(html)
	if len(match) > 1 {
		return strings.TrimSpace(match[1])
	}
	return ""
}

// extractDescription searches for the description meta tag in the HTML string
func extractDescription(html string) string {
	// Try standard order: name then content
	match := descRegex1.FindStringSubmatch(html)
	if len(match) > 1 {
		return strings.TrimSpace(match[1])
	}

	// Try reverse order: content then name
	match = descRegex2.FindStringSubmatch(html)
	if len(match) > 1 {
		return strings.TrimSpace(match[1])
	}

	return ""
}

func main() {
	e := echo.New()

	// Standard middleware
	e.Use(middleware.Logger())
	e.Use(middleware.Recover())

	// Register the handler under the /preview path
	e.POST("/preview", FetchURLPreview)

	// Start the server on port 8080
	e.Logger.Fatal(e.Start(":8080"))
}

