package main

import (
	"bytes"
	"fmt"
	"io"
	"net/http"
	"net/url"
	"strings"
	"time"

	"github.com/labstack/echo/v4"
	"github.com/labstack/echo/v4/middleware"
	"golang.org/x/net/html"
)

// PreviewRequest defines the input structure
type PreviewRequest struct {
	URL string `json:"url"`
}

// PreviewResponse defines the output structure
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
}

func main() {
	e := echo.New()

	// Middleware
	e.Use(middleware.Logger())
	e.Use(middleware.Recover())

	// Routes
	e.POST("/preview", FetchURLPreview)

	// Start server
	e.Logger.Fatal(e.Start(":8080"))
}

// FetchURLPreview handles the URL preview logic
func FetchURLPreview(ctx echo.Context) error {
	req := new(PreviewRequest)
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON"})
	}

	// Validate URL
	parsedURL, err := url.ParseRequestURI(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL format"})
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Only HTTP/HTTPS URLs are allowed"})
	}

	// Fetch the URL
	client := &http.Client{
		Timeout: 5 * time.Second,
	}

	httpReq, err := http.NewRequestWithContext(ctx.Request().Context(), http.MethodGet, parsedURL.String(), nil)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to create request"})
	}

	// Set a browser-like User-Agent to avoid being blocked by some sites
	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0; +http://localhost:8080)")
	httpReq.Header.Set("Accept", "text/html")

	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": fmt.Sprintf("Remote server returned HTTP %d", resp.StatusCode)})
	}

	// Limit reading to 1MB to prevent memory exhaustion
	limitReader := io.LimitReader(resp.Body, 1024*1024)
	body, err := io.ReadAll(limitReader)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response body"})
	}

	title, description := extractTitleAndDescription(body)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// extractTitleAndDescription parses the HTML to find the title and meta description
func extractTitleAndDescription(htmlContent []byte) (string, string) {
	var title, description string
	tokenizer := html.NewTokenizer(bytes.NewReader(htmlContent))

	for {
		tokenType := tokenizer.Next()
		if tokenType == html.ErrorToken {
			break
		}

		token := tokenizer.Token()

		// Handle Title Tag
		if tokenType == html.StartTagToken && token.Data == "title" {
			tokenType = tokenizer.Next()
			if tokenType == html.TextToken {
				title = strings.TrimSpace(tokenizer.Token().Data)
			}
		}

		// Handle Meta Tags (Description and OpenGraph Description)
		if tokenType == html.SelfClosingTagToken || tokenType == html.StartTagToken {
			if token.Data == "meta" {
				var name, property, content string
				for _, attr := range token.Attr {
					switch attr.Key {
					case "name":
						name = attr.Val
					case "property":
						property = attr.Val
					case "content":
						content = attr.Val
					}
				}

				// Prioritize standard description, fallback to og:description
				if (name == "description" || property == "og:description") && description == "" {
					description = strings.TrimSpace(content)
				}
			}
		}

		// Optimization: If we have both, we can stop (though simple bots usually parse the whole head)
		if title != "" && description != "" && token.Data == "body" {
			break
		}
	}

	return title, description
}

