const (
	MaxResponseBodySize = 1024 * 1024 // 1MB limit
	FetchTimeout        = 5 * time.Second
)

// isSafeAddr checks if the resolved address is a public, non-local IP.
func isSafeAddr(address string) error {
	host, _, err := net.SplitHostPort(address)
	if err != nil {
		return err
	}
	ip := net.ParseIP(host)
	if ip == nil {
		return errors.New("invalid IP address")
	}

	// Block Loopback, Link-Local, Private (RFC 1918/4193), and Unspecified addresses
	if ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() || ip.IsPrivate() || ip.IsUnspecified() {
		return fmt.Errorf("access to internal/private network address %s is prohibited", host)
	}
	return nil
}

// createSafeClient returns an http.Client configured to prevent SSRF and resource exhaustion.
func createSafeClient() *http.Client {
	return &http.Client{
		Timeout: FetchTimeout,
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			if len(via) >= 5 {
				return errors.New("too many redirects")
			}
			return nil
		},
		Transport: &http.Transport{
			DialContext: (&net.Dialer{
				Timeout:   3 * time.Second,
				KeepAlive: 30 * time.Second,
				// Control is called after DNS resolution but before connection.
				// This is the most effective way to prevent SSRF and DNS Rebinding.
				Control: func(network, address string, c syscall.RawConn) error {
					return isSafeAddr(address)
				},
			}).DialContext,
			ResponseHeaderTimeout: 3 * time.Second,
		},
	}
}

func FetchURLPreview(ctx echo.Context) error {
	req := new(PreviewRequest)
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON"})
	}

	parsedURL, err := url.Parse(req.URL)
	if err != nil || parsedURL.Scheme == "" || parsedURL.Host == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL format"})
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Only HTTP/HTTPS URLs are allowed"})
	}

	client := createSafeClient()
	httpReq, err := http.NewRequestWithContext(ctx.Request().Context(), http.MethodGet, parsedURL.String(), nil)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to create request"})
	}
	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "Failed to fetch URL content"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "Target server returned an error"})
	}

	// Check content type to avoid parsing large non-HTML files
	contentType := resp.Header.Get("Content-Type")
	if !strings.Contains(strings.ToLower(contentType), "text/html") {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL is not an HTML page"})
	}

	// Limit the amount of data read into memory to prevent DoS
	limitedReader := io.LimitReader(resp.Body, MaxResponseBodySize)
	title, description := extractTitleAndDescription(limitedReader)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

func extractTitleAndDescription(r io.Reader) (string, string) {
	var title, description string
	tokenizer := html.NewTokenizer(r)

	for {
		tokenType := tokenizer.Next()
		if tokenType == html.ErrorToken {
			break
		}

		token := tokenizer.Token()
		if tokenType == html.StartTagToken {
			if token.Data == "title" {
				if tokenizer.Next() == html.TextToken {
					title = strings.TrimSpace(tokenizer.Token().Data)
				}
			} else if token.Data == "meta" {
				var name, content string
				for _, attr := range token.Attr {
					if strings.ToLower(attr.Key) == "name" {
						name = strings.ToLower(attr.Val)
					} else if strings.ToLower(attr.Key) == "content" {
						content = attr.Val
					}
				}
				if name == "description" {
					description = content
				}
			}
		}

		// Stop if we have both
		if title != "" && description != "" {
			break
		}
	}

	return title, description
}

func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)
	e.Logger.Fatal(e.Start(":8080"))
}

