// PreviewRequest defines the input structure for the handler
type PreviewRequest struct {
	URL string `json:"url"`
}

// PreviewResponse defines the output structure for the handler
type PreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

// FetchURLPreview handles the POST /preview request
func FetchURLPreview(c echo.Context) error {
	req := new(PreviewRequest)
	if err := c.Bind(req); err != nil {
		return c.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid request body"})
	}

	if req.URL == "" {
		return c.JSON(http.StatusBadRequest, map[string]string{"error": "URL is required"})
	}

	// Set timeout to 3 seconds as required
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(req.URL)
	if err != nil {
		return c.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL: " + err.Error()})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return c.JSON(http.StatusBadGateway, map[string]string{"error": "Remote server returned status: " + resp.Status})
	}

	title, description := parseHTML(resp.Body)

	return c.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// parseHTML extracts the title and meta description from the HTML body
func parseHTML(body io.Reader) (string, string) {
	var title, description string
	tokenizer := html.NewTokenizer(body)

	for {
		tokenType := tokenizer.Next()
		if tokenType == html.ErrorToken {
			break
		}

		token := tokenizer.Token()

		// Extract Title
		if tokenType == html.StartTagToken && token.Data == "title" {
			tokenType = tokenizer.Next()
			if tokenType == html.TextToken {
				title = strings.TrimSpace(tokenizer.Token().Data)
			}
		}

		// Extract Meta Description
		if tokenType == html.SelfClosingTagToken || tokenType == html.StartTagToken {
			if token.Data == "meta" {
				var isDescription bool
				var content string
				for _, attr := range token.Attr {
					if strings.ToLower(attr.Key) == "name" && strings.ToLower(attr.Val) == "description" {
						isDescription = true
					}
					if strings.ToLower(attr.Key) == "content" {
						content = attr.Val
					}
				}
				if isDescription {
					description = content
				}
			}
		}

		// Optimization: if we have both, we can stop early (optional)
		// but since pages can have multiple meta tags, we usually iterate through head.
	}

	return title, description
}

func main() {
	e := echo.New()

	// Middleware
	e.Use(middleware.Logger())
	e.Use(middleware.Recover())

	// Routes
	e.POST("/preview", FetchURLPreview)

	// Start server
	e.Logger.Fatal(e.Start(":8080"))
}

