package main

import (
	"io"
	"net/http"
	"strings"
	"time"

	"github.com/labstack/echo/v4"
	"github.com/labstack/echo/v4/middleware"
	"golang.org/x/net/html"
)

// PreviewRequest defines the input structure for the /preview endpoint.
type PreviewRequest struct {
	URL string `json:"url"`
}

// PreviewResponse defines the output structure for the /preview endpoint.
type PreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

// FetchURLPreview is the handler that fetches a URL and extracts its title and meta description.
func FetchURLPreview(ctx echo.Context) error {
	req := new(PreviewRequest)
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid request body"})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL is required"})
	}

	// Create HTTP client with a 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL: " + err.Error()})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "Target URL returned non-200 status"})
	}

	title, description := parseHTML(resp.Body)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// parseHTML extracts the <title> and <meta name="description"> from an HTML stream.
func parseHTML(r io.Reader) (string, string) {
	var title, description string
	var inTitle bool

	tokenizer := html.NewTokenizer(r)

	for {
		tokenType := tokenizer.Next()

		switch tokenType {
		case html.ErrorToken:
			// End of document or error
			return title, description

		case html.StartTagToken, html.SelfClosingTagToken:
			token := tokenizer.Token()
			if token.Data == "title" {
				inTitle = true
			}
			if token.Data == "meta" {
				var name, content string
				for _, attr := range token.Attr {
					key := strings.ToLower(attr.Key)
					if key == "name" || key == "property" { // Support og:description as fallback if needed, but strictly "description" per requirement
						if strings.ToLower(attr.Val) == "description" {
							name = "description"
						}
					}
					if key == "content" {
						content = attr.Val
					}
				}
				if name == "description" {
					description = content
				}
			}

		case html.TextToken:
			if inTitle {
				title = strings.TrimSpace(tokenizer.Token().Data)
				inTitle = false // Only take the first text node in title
			}

		case html.EndTagToken:
			token := tokenizer.Token()
			if token.Data == "title" {
				inTitle = false
			}
		}

		// Optimization: if both found, we could break, but meta tags can appear anywhere in head
	}
}

func main() {
	e := echo.New()

	// Middleware
	e.Use(middleware.Logger())
	e.Use(middleware.Recover())

	// Routes
	e.POST("/preview", FetchURLPreview)

	// Start server
	e.Logger.Fatal(e.Start(":8080"))
}

