// isSafeIP checks if an IP address is public and not part of private/reserved ranges.
func isSafeIP(ip net.IP) bool {
	if ip == nil {
		return false
	}
	// Check for loopback, link-local, and multicast
	if ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return false
	}
	// Check for private IPv4 and IPv6 ranges (Go 1.17+)
	if ip4 := ip.To4(); ip4 != nil {
		return !ip4.IsPrivate()
	}
	return !ip.IsPrivate()
}

// safeHTTPClient is configured to mitigate SSRF and DNS Rebinding.
var safeHTTPClient = &http.Client{
	Timeout: 10 * time.Second,
	Transport: &http.Transport{
		DialContext: (&net.Dialer{
			Timeout:   3 * time.Second,
			KeepAlive: 30 * time.Second,
			// Control is called after DNS resolution but before the connection is established.
			// This is the most effective way to prevent SSRF and DNS Rebinding.
			Control: func(network, address string, c syscall.RawConn) error {
				host, _, err := net.SplitHostPort(address)
				if err != nil {
					return err
				}
				ip := net.ParseIP(host)
				if !isSafeIP(ip) {
					return errors.New("access to internal or private network is prohibited")
				}
				return nil
			},
		}).DialContext,
		// Disable Keep-Alives to ensure every request goes through the DialContext check
		// and to prevent connection reuse to hosts that might have changed IP.
		DisableKeepAlives: true,
	},
	CheckRedirect: func(req *http.Request, via []*http.Request) error {
		if len(via) >= 3 {
