		return nil
	},
}

// FetchURLPreview handles the URL preview request.
func FetchURLPreview(ctx echo.Context) error {
	req := new(PreviewRequest)
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON"})
	}

	parsedURL, err := url.Parse(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL format"})
	}

	// Only allow standard web protocols
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Only HTTP/HTTPS URLs are allowed"})
	}

	// Create a request with the request's context for cancellation support
	request, err := http.NewRequestWithContext(ctx.Request().Context(), http.MethodGet, parsedURL.String(), nil)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Internal error"})
	}
	request.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	resp, err := safeHTTPClient.Do(request)
	if err != nil {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "Failed to fetch URL: " + err.Error()})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": fmt.Sprintf("Remote server returned status %d", resp.StatusCode)})
	}

	// Limit reading to 1MB to prevent memory exhaustion (Resource Exhaustion)
	limitReader := io.LimitReader(resp.Body, 1*1024*1024)
	body, err := io.ReadAll(limitReader)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response content"})
	}

	title, description := extractTitleAndDescription(body)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// extractTitleAndDescription uses regex to find basic HTML metadata.
func extractTitleAndDescription(htmlContent []byte) (string, string) {
	content := string(htmlContent)

	// Extract Title
	titleRegexp := regexp.MustCompile(`(?i)<title[^>]*>(.*?)</title>`)
	titleMatch := titleRegexp.FindStringSubmatch(content)
	title := ""
	if len(titleMatch) > 1 {
		title = strings.TrimSpace(titleMatch[1])
	}

	// Extract Meta Description (handles name="description" before or after content attribute)
	var description string
	descRegexp := regexp.MustCompile(`(?i)<meta\s+[^>]*name=["']description["'][^>]*content=["']([^"']*)["']`)
	descMatch := descRegexp.FindStringSubmatch(content)
	if len(descMatch) > 1 {
		description = strings.TrimSpace(descMatch[1])
	} else {
		descRegexpAlt := regexp.MustCompile(`(?i)<meta\s+[^>]*content=["']([^"']*)["'][^>]*name=["']description["']`)
		descMatchAlt := descRegexpAlt.FindStringSubmatch(content)
		if len(descMatchAlt) > 1 {
			description = strings.TrimSpace(descMatchAlt[1])
		}
	}

	// Basic sanitization of entities
	title = strings.ReplaceAll(title, "&amp;", "&")
	title = strings.ReplaceAll(title, "&lt;", "<")
	title = strings.ReplaceAll(title, "&gt;", ">")

	return title, description
}

func main() {
	e := echo.New()

	// Register the handler
	e.POST("/preview", FetchURLPreview)

	e.Logger.Fatal(e.Start(":8080"))
}

