// FetchURLPreview handles POST /preview requests to extract metadata from a given URL.
// It sets a 3-second timeout for the fetch operation as required.
func FetchURLPreview(ctx echo.Context) error {
	// Parse the request body
	req := new(PreviewRequest)
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid request body"})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL is required"})
	}

	// Configure HTTP client with a 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Fetch the content from the provided URL
	resp, err := client.Get(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL: " + err.Error()})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "Target URL returned status " + resp.Status})
	}

	// Parse the HTML content
	doc, err := html.Parse(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to parse HTML content"})
	}

	var title, description string

	// Recursive function to traverse the HTML tree
	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract <title> tag content
			if n.Data == "title" {
				var sb strings.Builder
				for c := n.FirstChild; c != nil; c = c.NextSibling {
					if c.Type == html.TextNode {
						sb.WriteString(c.Data)
					}
				}
				title = sb.String()
			}

			// Extract <meta name="description"> content
			if n.Data == "meta" {
				var isDesc bool
				var content string
				for _, attr := range n.Attr {
					key := strings.ToLower(attr.Key)
					val := attr.Val
					if key == "name" && strings.ToLower(val) == "description" {
						isDesc = true
					}
					if key == "content" {
						content = val
					}
				}
				if isDesc {
					description = content
				}
			}
		}

		// Continue traversal
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)

	// Return the extracted metadata as JSON
	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       strings.TrimSpace(title),
		Description: strings.TrimSpace(description),
	})
}

func main() {
	// Initialize Echo framework
	e := echo.New()

	// Register the handler under the /preview path
	e.POST("/preview", FetchURLPreview)

	// Start the server on port 8080
	e.Logger.Fatal(e.Start(":8080"))
}

