// PreviewRequest defines the structure for the incoming JSON request body.
type PreviewRequest struct {
	URL string `json:"url"`
}

// PreviewResponse defines the structure for the outgoing JSON response.
type PreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

// FetchURLPreview handles POST requests to /preview, fetches the URL content,
// and extracts the page title and meta description.
func FetchURLPreview(ctx echo.Context) error {
	req := new(PreviewRequest)
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "invalid request body"})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "url field is required"})
	}

	// Create an HTTP client with a 3-second timeout as required.
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Fetch the content from the provided URL.
	resp, err := client.Get(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "failed to fetch URL: " + err.Error()})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "target URL returned non-200 status"})
	}

	// Read a limited portion of the body (512KB is usually plenty for HTML head metadata).
	bodyBytes, err := io.ReadAll(io.LimitReader(resp.Body, 512*1024))
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "failed to read page content"})
	}
	body := string(bodyBytes)

	// Extract Title and Meta Description using regex.
	title := extractTitle(body)
	description := extractDescription(body)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// extractTitle finds the content within the <title> tag.
func extractTitle(html string) string {
	// (?is) flag: i = case-insensitive, s = let . match newline
	re := regexp.MustCompile(`(?is)<title>(.*?)</title>`)
	matches := re.FindStringSubmatch(html)
	if len(matches) > 1 {
		return strings.TrimSpace(matches[1])
	}
	return ""
}

// extractDescription finds the content of the <meta name="description" content="..."> tag.
func extractDescription(html string) string {
	// Match <meta name="description" content="...">
	re1 := regexp.MustCompile(`(?is)<meta\s+[^>]*name=["']description["'][^>]*content=["']([^"']+)["']`)
	if matches := re1.FindStringSubmatch(html); len(matches) > 1 {
		return strings.TrimSpace(matches[1])
	}

	// Match <meta content="..." name="description"> (alternative attribute order)
	re2 := regexp.MustCompile(`(?is)<meta\s+[^>]*content=["']([^"']+)["'][^>]*name=["']description["']`)
	if matches := re2.FindStringSubmatch(html); len(matches) > 1 {
		return strings.TrimSpace(matches[1])
	}

	return ""
}

func main() {
	e := echo.New()

	// Register the handler under the /preview path as required.
	e.POST("/preview", FetchURLPreview)

	// Start the Echo server on port 8080.
	e.Logger.Fatal(e.Start(":8080"))
}

